import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(proj, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return result

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(list(b.keys()) + list(a.keys())))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('None')
print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]} = {u[3]}')
"

